def {{nama_fungsi}}(name, bases=(), **attrs):
    """Create a new class dynamically.
    make_class('Dog', (Animal,), sound='Woof')
    """
    return type(name, bases, attrs)


def {{nama_fungsi_ext}}(name, fields=None, methods=None, bases=(), doc=None):
    """Build a class with fields (class vars) and methods.
    fields: dict of name: default_value
    methods: dict of name: callable
    Returns the new class.
    """
    attrs = {}
    if doc:
        attrs['__doc__'] = doc
    if fields:
        for fname, default in fields.items():
            attrs[fname] = default
    if methods:
        attrs.update(methods)

    def __init__(self, **kwargs):
        for key, val in (fields or {}).items():
            setattr(self, key, kwargs.get(key, val))
    attrs.setdefault('__init__', __init__)

    def __repr__(self):
        parts = ['%s=%r' % (k, getattr(self, k, None)) for k in (fields or {})]
        return self.__class__.__name__ + '(' + ', '.join(parts) + ')'
    attrs.setdefault('__repr__', __repr__)

    return type(name, bases, attrs)

def {{nama_fungsi}}(class_name, fields, use_annotations={{use_annotations}}, frozen=False, slots=False):
    """Generate @dataclass Python code from field definitions.
    fields: list of {'name': str, 'type': str, 'default': any, 'required': bool}
    Returns Python source code as string.
    """
    imports = ['from dataclasses import dataclass']
    if any(f.get('type') in ('List', 'Dict', 'Optional') for f in fields):
        imports.append('from typing import List, Dict, Optional')
    lines = list(imports) + ['', '@dataclass(frozen=' + str(frozen) + (', slots=True' if slots else '') + ')']
    lines.append('class ' + class_name + ':')
    has_doc = False
    for f in fields:
        if f.get('doc'):
            lines.append('    """' + f['doc'] + '"""')
            has_doc = True
            break
    required = [f for f in fields if f.get('required', True)]
    optional = [f for f in fields if not f.get('required', True)]
    for f in required + optional:
        name = f['name']
        ftype = f.get('type', 'str')
        if use_annotations:
            if 'default' in f and f['default'] is not None:
                default_repr = repr(f['default'])
                lines.append('    %s: %s = %s' % (name, ftype, default_repr))
            else:
                lines.append('    %s: %s' % (name, ftype))
        else:
            if 'default' in f and f['default'] is not None:
                lines.append('    %s = %r' % (name, f['default']))
            else:
                lines.append('    %s = None' % name)
    if not fields and not has_doc:
        lines.append('    pass')
    return '\n'.join(lines) + '\n'

def {{nama_fungsi}}(*mixins, base=None):
    """Compose multiple mixin classes into one.
    Returns a new class that inherits from all mixins + optional base.
    Later mixins override earlier ones (MRO order).
    """
    bases = tuple(mixins)
    if base is not None:
        bases = bases + (base,)
    name = '_'.join(m.__name__ for m in mixins) + '_Composed'
    return type(name, bases, {})


def {{nama_fungsi_named}}(name, *mixins, base=None):
    """Like compose_mixins but with a custom name."""
    bases = tuple(mixins)
    if base is not None:
        bases = bases + (base,)
    return type(name, bases, {})


def has_method(obj, method_name):
    """Check if object has a specific method (not just attribute)."""
    method = getattr(obj, method_name, None)
    return callable(method)


def list_methods(cls):
    """List all public methods of a class (excluding dunder)."""
    return [name for name in dir(cls) if callable(getattr(cls, name, None)) and not name.startswith('_')]

class {{nama_metaclass}}(type):
    """Singleton metaclass. Usage: class MyClass(metaclass=SingletonMeta): ...
    Only one instance of MyClass can ever exist.
    """
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

    @classmethod
    def reset(mcs, cls):
        """Reset the singleton instance (useful for testing)."""
        mcs._instances.pop(cls, None)


def {{nama_decorator}}(cls):
    """Singleton decorator alternative. Usage: @singleton class MyClass: ...
    Wraps __init__ to prevent re-initialization.
    """
    instances = {}
    original_init = cls.__init__

    @functools.wraps(cls.__init__)
    def __init__(self, *args, **kwargs):
        if not getattr(self, '_initialized', False):
            original_init(self, *args, **kwargs)
            self._initialized = True

    cls.__init__ = __init__

    original_new = cls.__new__ if hasattr(cls, '__new__') and cls.__new__ is not object.__new__ else None

    def __new__(klass, *args, **kwargs):
        if cls not in instances:
            if original_new:
                instance = original_new(klass)
            else:
                instance = object.__new__(klass)
            instances[cls] = instance
        return instances[cls]

    cls.__new__ = __new__
    cls._reset_singleton = lambda: instances.pop(cls, None)
    return cls

class {{nama_fungsi}}:
    """Descriptor that triggers callbacks on value change.
    class Config:
        debug = observable(False)
    c = Config()
    c.debug = True  # triggers callbacks
    """
    def __init__(self, initial_value=None, name=None):
        self._name = name
        self._initial = initial_value
        self._callbacks = []

    def __set_name__(self, owner, name):
        self._name = name

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        return obj.__dict__.get('_obs_' + self._name, self._initial)

    def __set__(self, obj, value):
        old = self.__get__(obj)
        obj.__dict__['_obs_' + self._name] = value
        if old != value:
            for callback in obj.__dict__.get('_obs_callbacks_' + self._name, []):
                callback(self._name, old, value)

    def on_change(self, callback):
        """Register a callback for changes. Use as class-level setup."""
        self._callbacks.append(callback)
        return self


class {{nama_class}}:
    """Mixin that adds observer support for observable properties.
    class Config(ObservableMixin):
        name = observable('default')
    c = Config()
    c.watch('name', lambda attr, old, new: print(f'{attr}: {old} -> {new}'))
    """
    def watch(self, attr_name, callback):
        """Watch for changes on an observable attribute."""
        key = '_obs_callbacks_' + attr_name
        if key not in self.__dict__:
            self.__dict__[key] = []
        self.__dict__[key].append(callback)

    def unwatch(self, attr_name, callback=None):
        """Remove callback(s) for an attribute."""
        key = '_obs_callbacks_' + attr_name
        if callback:
            self.__dict__.get(key, []).remove(callback)
        else:
            self.__dict__.pop(key, None)

def {{nama_decorator}}(cls=None, hide_private=True, max_items=None):
    """Auto-generate __repr__ from instance attributes.
    @auto_repr
    class Point:
        def __init__(self, x, y):
            self.x = x
            self.y = y
    repr(Point(1, 2)) → 'Point(x=1, y=2)'
    """
    def decorator(klass):
        def __repr__(self):
            attrs = vars(self)
            if hide_private:
                attrs = {k: v for k, v in attrs.items() if not k.startswith('_')}
            parts = []
            for k, v in attrs.items():
                if max_items and len(parts) >= max_items:
                    parts.append('...')
                    break
                parts.append('%s=%r' % (k, v))
            return klass.__name__ + '(' + ', '.join(parts) + ')'
        klass.__repr__ = __repr__
        return klass

    if cls is not None:
        return decorator(cls)
    return decorator


def {{nama_decorator_str}}(cls=None, **kwargs):
    """Like auto_repr but also sets __str__ = __repr__."""
    def decorator(klass):
        klass = {{nama_decorator}}(cls=klass, **kwargs)
        klass.__str__ = klass.__repr__
        return klass
    if cls is not None:
        return decorator(cls)
    return decorator

def {{nama_fungsi}}(cls, interface):
    """Check if cls implements all public methods of interface.
    Returns dict with 'complete' (bool), 'missing' (list), 'matches' (list).
    """
    required = set()
    for name, method in inspect.getmembers(interface, predicate=inspect.isfunction):
        if not name.startswith('_'):
            required.add(name)
    implemented = set()
    for name in required:
        if hasattr(cls, name) and callable(getattr(cls, name, None)):
            implemented.add(name)
    missing = required - implemented
    return {
        'complete': len(missing) == 0,
        'missing': sorted(missing),
        'matches': sorted(implemented),
        'required': sorted(required),
    }


def {{nama_decorator}}(interface):
    """Decorator that validates a class implements an interface at definition time.
    Raises TypeError if any methods are missing.
    Usage: @implements(MyInterface) class MyClass: ...
    """
    def decorator(cls):
        result = {{nama_fungsi}}(cls, interface)
        if not result['complete']:
            raise TypeError('%s does not implement %s. Missing: %s' % (
                cls.__name__, interface.__name__, ', '.join(result['missing'])
            ))
        cls.__implements__ = interface
        return cls
    return decorator

class {{nama_class}}:
    """Simple IoC container for dependency injection.
    c = Container()
    c.register('db', Database('localhost'))
    c.register('cache', Cache())
    @c.inject
    def handler(db, cache):
        ...
    """
    def __init__(self):
        self._registry = {}
        self._factories = {}

    def register(self, name, instance):
        """Register a pre-built instance."""
        self._registry[name] = instance
        return self

    def register_factory(self, name, factory):
        """Register a factory function (called lazily, result cached)."""
        self._factories[name] = factory
        return self

    def get(self, name, default=None):
        """Get a registered dependency by name."""
        if name in self._registry:
            return self._registry[name]
        if name in self._factories:
            self._registry[name] = self._factories[name]()
            del self._factories[name]
            return self._registry[name]
        return default

    def inject(self, func):
        """Decorator: inject registered dependencies into function parameters."""
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            sig = inspect.signature(func)
            for param_name, param in sig.parameters.items():
                if param_name not in kwargs and param_name not in ('args', 'kwargs'):
                    dep = self.get(param_name)
                    if dep is not None:
                        kwargs[param_name] = dep
            return func(*args, **kwargs)
        return wrapper

    def has(self, name):
        return name in self._registry or name in self._factories

    def clear(self):
        self._registry.clear()
        self._factories.clear()
